class Solution {
public:
    int getKth(int lo, int hi, int k) {
        vector<pair<int, int>> nums(hi - lo + 1);
        for (int i = lo; i <= hi; i++) {
            int power = 0;
            int x = i;
            while (x != 1) {
                power++;
                x = (x % 2 == 0) ? x / 2 : 3 * x + 1;
            }
            nums[i - lo] = {power, i};
        }
        sort(nums.begin(), nums.end());
        return nums[k - 1].second;
    }
};
